1	import { jwtVerify, SignJWT, createRemoteJWKSet } from 'jose';
2	import type { Env, JWTPayload } from '../types';
3	import { createSupabaseClient } from '../lib/supabase';
4	import { isValidUUID } from '../lib/security';
5	
6	// Cache JWKS per Supabase URL to avoid re-fetching on every request.
7	// createRemoteJWKSet handles its own HTTP caching internally.
8	const jwksCache = new Map<string, ReturnType<typeof createRemoteJWKSet>>();
9	
10	function getJWKS(supabaseUrl: string): ReturnType<typeof createRemoteJWKSet> {
11	  let jwks = jwksCache.get(supabaseUrl);
12	  if (!jwks) {
13	    jwks = createRemoteJWKSet(new URL(`${supabaseUrl}/auth/v1/.well-known/jwks.json`));
14	    jwksCache.set(supabaseUrl, jwks);
15	  }
16	  return jwks;
17	}
18	
19	const JWT_EXPIRY = '30d'; // 30 days for bots (matches SKILL.md docs, auto-refreshed during heartbeat)
20	const JWT_ISSUER = 'supabase';
21	const JWT_AUDIENCE = 'authenticated';
22	
23	/**
24	 * Generate a Supabase-compatible JWT for a bot.
25	 * Includes iss/aud claims so the token works with Supabase RLS policies.
26	 */
27	export async function generateBotJWT(
28	  botId: string,
29	  secret: string,
30	  options?: { verified?: boolean; supabaseRef?: string },
31	): Promise<{ token: string; jti: string }> {
32	  const secretKey = new TextEncoder().encode(secret);
33	  const jti = crypto.randomUUID();
34	
35	  const token = await new SignJWT({
36	    role: 'bot',
37	    verified: options?.verified ?? false,
38	    ref: options?.supabaseRef,
39	  })
40	    .setProtectedHeader({ alg: 'HS256', typ: 'JWT' })
41	    .setSubject(botId)
42	    .setIssuer(JWT_ISSUER)
43	    .setAudience(JWT_AUDIENCE)
44	    .setIssuedAt()
45	    .setExpirationTime(JWT_EXPIRY)
46	    .setJti(jti)
47	    .sign(secretKey);
48	
49	  return { token, jti };
50	}
51	
52	/**
53	 * Verify and decode a JWT. Validates signature, expiry, issuer, and audience.
54	 * Accepts multiple secrets for zero-downtime deployments and secret rotation.
55	 * Tries each secret in order; succeeds on first valid match.
56	 */
57	export async function validateJWT(token: string, ...secrets: string[]): Promise<JWTPayload> {
58	  const validSecrets = secrets.filter(Boolean);
59	  if (validSecrets.length === 0) {
60	    throw new Error('No JWT secrets provided');
61	  }
62	
63	  let lastError: unknown = new Error('JWT validation failed');
64	  for (const secret of validSecrets) {
65	    try {
66	      const secretKey = new TextEncoder().encode(secret);
67	      const { payload } = await jwtVerify(token, secretKey, {
68	        issuer: JWT_ISSUER,
69	        audience: JWT_AUDIENCE,
70	        algorithms: ['HS256'],
71	      });
72	
73	      if (!payload.sub) {
74	        throw new Error('JWT missing sub claim');
75	      }
76	
77	      return {
78	        sub: payload.sub,
79	        role: (payload as Record<string, unknown>).role as 'bot' | 'human',
80	        verified: (payload as Record<string, unknown>).verified as boolean,
81	        jti: payload.jti ?? '',
82	      };
83	    } catch (e) {
84	      lastError = e;
85	    }
86	  }
87	
88	  throw lastError;
89	}
90	
91	export function extractToken(request: Request): string | null {
92	  const auth = request.headers.get('Authorization');
93	  if (!auth?.startsWith('Bearer ')) return null;
94	  return auth.slice(7);
95	}
96	
97	/**
98	 * Validate JWT and check it against the blacklist table.
99	 * Returns the decoded payload or throws on failure.
100	 */
101	export async function validateJWTWithBlacklist(token: string, env: Env): Promise<JWTPayload> {
102	  const payload = await validateJWT(token, env.JWT_SECRET, ...(env.JWT_SECRET_PREVIOUS ? [env.JWT_SECRET_PREVIOUS] : []));
103	
104	  if (payload.jti) {
105	    const supabase = createSupabaseClient(env);
106	    const { data } = await supabase
107	      .from('jwt_blacklist')
108	      .select('jti')
109	      .eq('jti', payload.jti)
110	      .maybeSingle();
111	
112	    if (data) {
113	      throw new Error('Token has been revoked');
114	    }
115	  }
116	
117	  return payload;
118	}
119	
120	/**
121	 * Auth middleware: extracts and validates JWT from request.
122	 * Returns the payload if valid, or null if no token / invalid token.
123	 */
124	export async function authenticateRequest(
125	  request: Request,
126	  ...jwtSecrets: string[]
127	): Promise<JWTPayload | null> {
128	  const token = extractToken(request);
129	  if (!token) return null;
130	
131	  try {
132	    return await validateJWT(token, ...jwtSecrets);
133	  } catch {
134	    return null;
135	  }
136	}
137	
138	/**
139	 * Stricter auth middleware that returns a JSON error response on failure.
140	 * Use in routes that require authentication.
141	 */
142	export async function requireAuth(request: Request, env: Env): Promise<JWTPayload | Response> {
143	  const token = extractToken(request);
144	  if (!token) {
145	    return new Response(
146	      JSON.stringify({ error: 'Missing Authorization header' }),
147	      { status: 401, headers: { 'Content-Type': 'application/json' } },
148	    );
149	  }
150	
151	  try {
152	    const payload = await validateJWTWithBlacklist(token, env);
153	    if (!isValidUUID(payload.sub)) {
154	      return new Response(
155	        JSON.stringify({ error: 'Invalid token' }),
156	        { status: 401, headers: { 'Content-Type': 'application/json' } },
157	      );
158	    }
159	    return payload;
160	  } catch (error) {
161	    const message = error instanceof Error ? error.message : 'Invalid token';
162	    return new Response(
163	      JSON.stringify({ error: message }),
164	      { status: 401, headers: { 'Content-Type': 'application/json' } },
165	    );
166	  }
167	}
168	
169	/**
170	 * Auth middleware for human users (Supabase Auth tokens).
171	 * Validates JWT and checks role is 'authenticated' (not 'bot').
172	 * Returns { userId: string } or a 401/403 Response.
173	 */
174	export async function requireHumanAuth(request: Request, env: Env): Promise<{ userId: string } | Response> {
175	  const token = extractToken(request);
176	  if (!token) {
177	    return new Response(
178	      JSON.stringify({ error: 'Missing Authorization header' }),
179	      { status: 401, headers: { 'Content-Type': 'application/json' } },
180	    );
181	  }
182	
183	  if (!env.SUPABASE_URL) {
184	    console.error('[auth] SUPABASE_URL is not configured in Workers');
185	    return new Response(
186	      JSON.stringify({ error: 'Server misconfiguration: SUPABASE_URL not set' }),
187	      { status: 500, headers: { 'Content-Type': 'application/json' } },
188	    );
189	  }
190	
191	  try {
192	    // Supabase Auth tokens use ES256 (asymmetric ECDSA), not HS256.
193	    // Verify using the project's JWKS public key endpoint.
194	    const jwks = getJWKS(env.SUPABASE_URL);
195	    const { payload } = await jwtVerify(token, jwks, {
196	      audience: JWT_AUDIENCE,
197	      issuer: `${env.SUPABASE_URL}/auth/v1`,
198	    });
199	    if (!payload.sub) throw new Error('JWT missing sub claim');
200	
201	    // Human Supabase tokens have role 'authenticated', not 'bot'
202	    const role = payload.role as string | undefined;
203	    if (role === 'bot') {
204	      return new Response(
205	        JSON.stringify({ error: 'Human authentication required' }),
206	        { status: 403, headers: { 'Content-Type': 'application/json' } },
207	      );
208	    }
209	
210	    return { userId: payload.sub };
211	  } catch (error) {
212	    const message = error instanceof Error ? error.message : 'Invalid token';
213	    console.error('[auth] requireHumanAuth validation failure:', message);
214	    // Return generic message — don't leak jose internals (claim names, timestamps, algorithms)
215	    const hint = message.includes('exp')
216	      ? 'Token has expired — try refreshing the page'
217	      : 'Try signing out and back in';
218	    return new Response(
219	      JSON.stringify({ error: 'Invalid or expired token', hint }),
220	      { status: 401, headers: { 'Content-Type': 'application/json' } },
221	    );
222	  }
223	}
224	
225	/**
226	 * Like requireAuth but also checks that the bot is verified.
227	 */
228	export async function requireVerifiedBot(request: Request, env: Env): Promise<JWTPayload | Response> {
229	  const result = await requireAuth(request, env);
230	  if (result instanceof Response) return result;
231	
232	  if (result.role !== 'bot') {
233	    return new Response(
234	      JSON.stringify({ error: 'Bot authentication required' }),
235	      { status: 403, headers: { 'Content-Type': 'application/json' } },
236	    );
237	  }
238	
239	  if (!result.verified) {
240	    return new Response(
241	      JSON.stringify({ error: 'Bot is not verified' }),
242	      { status: 403, headers: { 'Content-Type': 'application/json' } },
243	    );
244	  }
245	
246	  return result;
247	}
