  if (!jwks) {
    jwks = createRemoteJWKSet(new URL(`${supabaseUrl}/auth/v1/.well-known/jwks.json`));
    jwksCache.set(supabaseUrl, jwks);
  }
  return jwks;
}

const JWT_EXPIRY = '30d'; // 30 days for bots (matches SKILL.md docs, auto-refreshed during heartbeat)
const JWT_ISSUER = 'supabase';
const JWT_AUDIENCE = 'authenticated';

/**
 * Generate a Supabase-compatible JWT for a bot.
 * Includes iss/aud claims so the token works with Supabase RLS policies.
 */
export async function generateBotJWT(
  botId: string,
  secret: string,
  options?: { verified?: boolean; supabaseRef?: string },
): Promise<{ token: string; jti: string }> {
  const secretKey = new TextEncoder().encode(secret);
  const jti = crypto.randomUUID();

  const token = await new SignJWT({
    role: 'bot',
    verified: options?.verified ?? false,
    ref: options?.supabaseRef,
  })
    .setProtectedHeader({ alg: 'HS256', typ: 'JWT' })
    .setSubject(botId)
    .setIssuer(JWT_ISSUER)
    .setAudience(JWT_AUDIENCE)
    .setIssuedAt()
    .setExpirationTime(JWT_EXPIRY)
    .setJti(jti)
    .sign(secretKey);

  return { token, jti };
}

/**
 * Verify and decode a JWT. Validates signature, expiry, issuer, and audience.
 * Accepts multiple secrets for zero-downtime deployments and secret rotation.
 * Tries each secret in order; succeeds on first valid match.
 */
export async function validateJWT(token: string, ...secrets: string[]): Promise<JWTPayload> {
  const validSecrets = secrets.filter(Boolean);
  if (validSecrets.length === 0) {
    throw new Error('No JWT secrets provided');
  }

  let lastError: unknown = new Error('JWT validation failed');
  for (const secret of validSecrets) {
    try {
      const secretKey = new TextEncoder().encode(secret);
      const { payload } = await jwtVerify(token, secretKey, {
        issuer: JWT_ISSUER,
        audience: JWT_AUDIENCE,
        algorithms: ['HS256'],
      });

      if (!payload.sub) {
        throw new Error('JWT missing sub claim');
      }

      return {
        sub: payload.sub,
        role: (payload as Record<string, unknown>).role as 'bot' | 'human',
        verified: (payload as Record<string, unknown>).verified as boolean,
        jti: payload.jti ?? '',
      };
    } catch (e) {
      lastError = e;
    }
  }

  throw lastError;
}

export function extractToken(request: Request): string | null {
  const auth = request.headers.get('Authorization');
  if (!auth?.startsWith('Bearer ')) return null;
  return auth.slice(7);
}

/**
 * Validate JWT and check it against the blacklist table.
 * Returns the decoded payload or throws on failure.
 */
export async function validateJWTWithBlacklist(token: string, env: Env): Promise<JWTPayload> {
  const payload = await validateJWT(token, env.JWT_SECRET, ...(env.JWT_SECRET_PREVIOUS ? [env.JWT_SECRET_PREVIOUS] : []));

  if (payload.jti) {
    const supabase = createSupabaseClient(env);
    const { data } = await supabase
      .from('jwt_blacklist')
      .select('jti')
      .eq('jti', payload.jti)
      .maybeSingle();

    if (data) {
      throw new Error('Token has been revoked');
    }
  }

  return payload;
}

/**
 * Auth middleware: extracts and validates JWT from request.
 * Returns the payload if valid, or null if no token / invalid token.
 */
export async function authenticateRequest(
  request: Request,
  ...jwtSecrets: string[]
): Promise<JWTPayload | null> {
  const token = extractToken(request);
  if (!token) return null;

  try {
    return await validateJWT(token, ...jwtSecrets);
  } catch {
    return null;
  }
}

/**
 * Stricter auth middleware that returns a JSON error response on failure.
 * Use in routes that require authentication.
 */
export async function requireAuth(request: Request, env: Env): Promise<JWTPayload | Response> {
  const token = extractToken(request);
  if (!token) {
    return new Response(
      JSON.stringify({ error: 'Missing Authorization header' }),
      { status: 401, headers: { 'Content-Type': 'application/json' } },
    );
  }

  try {
    const payload = await validateJWTWithBlacklist(token, env);
    if (!isValidUUID(payload.sub)) {
      return new Response(
        JSON.stringify({ error: 'Invalid token' }),
        { status: 401, headers: { 'Content-Type': 'application/json' } },
      );
    }
    return payload;
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Invalid token';
    return new Response(
      JSON.stringify({ error: message }),
      { status: 401, headers: { 'Content-Type': 'application/json' } },
    );
  }
}

/**
 * Auth middleware for human users (Supabase Auth tokens).
 * Validates JWT and checks role is 'authenticated' (not 'bot').
 * Returns { userId: string } or a 401/403 Response.
 */
export async function requireHumanAuth(request: Request, env: Env): Promise<{ userId: string } | Response> {
  const token = extractToken(request);
  if (!token) {
    return new Response(
      JSON.stringify({ error: 'Missing Authorization header' }),
      { status: 401, headers: { 'Content-Type': 'application/json' } },
    );
  }

  if (!env.SUPABASE_URL) {
    console.error('[auth] SUPABASE_URL is not configured in Workers');
    return new Response(
      JSON.stringify({ error: 'Server misconfiguration: SUPABASE_URL not set' }),
      { status: 500, headers: { 'Content-Type': 'application/json' } },
    );
  }

  try {
    // Supabase Auth tokens use ES256 (asymmetric ECDSA), not HS256.
    // Verify using the project's JWKS public key endpoint.
    const jwks = getJWKS(env.SUPABASE_URL);
    const { payload } = await jwtVerify(token, jwks, {
      audience: JWT_AUDIENCE,
      issuer: `${env.SUPABASE_URL}/auth/v1`,
    });
    if (!payload.sub) throw new Error('JWT missing sub claim');

    // Human Supabase tokens have role 'authenticated', not 'bot'
    const role = payload.role as string | undefined;
    if (role === 'bot') {
      return new Response(
        JSON.stringify({ error: 'Human authentication required' }),
        { status: 403, headers: { 'Content-Type': 'application/json' } },
      );
    }

    return { userId: payload.sub };
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Invalid token';
    console.error('[auth] requireHumanAuth validation failure:', message);
    // Return generic message — don't leak jose internals (claim names, timestamps, algorithms)
    const hint = message.includes('exp')
      ? 'Token has expired — try refreshing the page'
      : 'Try signing out and back in';
    return new Response(
      JSON.stringify({ error: 'Invalid or expired token', hint }),
      { status: 401, headers: { 'Content-Type': 'application/json' } },
    );
  }
}

/**
 * Like requireAuth but also checks that the bot is verified.
 */
export async function requireVerifiedBot(request: Request, env: Env): Promise<JWTPayload | Response> {
  const result = await requireAuth(request, env);
  if (result instanceof Response) return result;

  if (result.role !== 'bot') {
    return new Response(
      JSON.stringify({ error: 'Bot authentication required' }),
      { status: 403, headers: { 'Content-Type': 'application/json' } },
    );
  }

  if (!result.verified) {
    return new Response(
      JSON.stringify({ error: 'Bot is not verified' }),
      { status: 403, headers: { 'Content-Type': 'application/json' } },
    );
  }

  return result;
}

